diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index fdadf729fbd5..346d46bf7bc2 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7885,6 +7885,7 @@ static Instruction *foldFCmpFNegCommonOp(FCmpInst &I) {
   return new FCmpInst(Pred, Op0, Zero, "", &I);
 }

+
 Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   bool Changed = false;

@@ -8022,6 +8023,64 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
     }
   }

+  // fcmp eq/ne (abs(X)), 0.0 -> fcmp eq/ne X, 0.0
+  // Handle absolute value pattern: select (fcmp Pred X, 0.0), A, B
+  // where {A, B} = {X, fneg(X)} and the select implements abs(X).
+  if (match(Op1, m_AnyZeroFP()) &&
+      (Pred == FCmpInst::FCMP_OEQ || Pred == FCmpInst::FCMP_UEQ ||
+       Pred == FCmpInst::FCMP_ONE || Pred == FCmpInst::FCMP_UNE)) {
+    Value *CondLHS, *CondRHS;
+    FCmpInst::Predicate CondPred;
+    Value *TrueVal, *FalseVal;
+    // Match select with fcmp condition.
+    if (match(Op0, m_Select(m_FCmp(CondPred, m_Value(CondLHS), m_Value(CondRHS)),
+                            m_Value(TrueVal), m_Value(FalseVal)))) {
+      Value *X = nullptr;
+      
+      // Check if the comparison is X compared to 0.0 (any zero)
+      if (match(CondLHS, m_AnyZeroFP()) && !match(CondRHS, m_AnyZeroFP())) {
+        // Pattern: fcmp Pred 0.0, X
+        X = CondRHS;
+        // Swap predicate to get X compared to 0.0
+        CondPred = FCmpInst::getSwappedPredicate(CondPred);
+      } else if (match(CondRHS, m_AnyZeroFP()) && !match(CondLHS, m_AnyZeroFP())) {
+        // Pattern: fcmp Pred X, 0.0
+        X = CondLHS;
+      }
+      
+      if (X) {
+        // Check if TrueVal and FalseVal are {X, fneg(X)} in either order
+        bool TrueIsX = (TrueVal == X);
+        bool TrueIsNegX = match(TrueVal, m_FNeg(m_Specific(X)));
+        bool FalseIsX = (FalseVal == X);
+        bool FalseIsNegX = match(FalseVal, m_FNeg(m_Specific(X)));
+        
+        // Check if this implements abs(X)
+        bool IsAbsPattern = false;
+        
+        if (TrueIsX && FalseIsNegX) {
+          // Pattern: select (fcmp Pred X, 0.0), X, fneg(X)
+          // This is abs(X) if Pred is true when X >= 0
+          // Only OGE (X >= 0) and OLT (X < 0) with swapped branches work
+          if (CondPred == FCmpInst::FCMP_OGE || CondPred == FCmpInst::FCMP_OLT) {
+            IsAbsPattern = true;
+          }
+        } else if (TrueIsNegX && FalseIsX) {
+          // Pattern: select (fcmp Pred X, 0.0), fneg(X), X
+          // This is abs(X) if Pred is true when X < 0
+          // Only OLT (X < 0) and OGE (X >= 0) with swapped branches work
+          if (CondPred == FCmpInst::FCMP_OLT || CondPred == FCmpInst::FCMP_OGE) {
+            IsAbsPattern = true;
+          }
+        }
+        
+        if (IsAbsPattern) {
+          return new FCmpInst(Pred, X, ConstantFP::getZero(OpType), "", &I);
+        }
+      }
+    }
+  }
+
   // Ignore signbit of bitcasted int when comparing equality to FP 0.0:
   // fcmp oeq/une (bitcast X), 0.0 --> (and X, SignMaskC) ==/!= 0
   if (match(Op1, m_PosZeroFP()) &&
@@ -8180,3 +8239,4 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {

   return Changed ? &I : nullptr;
 }
